import "../index.css";
import { useState, useEffect } from "react";
import { Routes, Route, useNavigate } from "react-router-dom";
import { api } from "../utils/api.js";
import Header from "./Header/Header.jsx";
import Main from "./Main/Main.jsx";
import Footer from "./Footer/Footer.jsx";
import Popup from "./Main/components/popup/Popup.jsx";
import CurrentUserContext from "../contexts/CurrentUserContext.js";
import InfoToolTip from "./InfoToolTip.jsx";
import { Register } from "./Register.jsx";
import { Login } from "./Login.jsx";
import ProtectedRoute from "./ProtectedRoute";
import * as auth from "../utils/auth.js";
import * as token from "../utils/token.js";

function App() {
  const [currentUser, setCurrentUser] = useState({ name: "User" });
  const [popup, setPopup] = useState(null);

  const [cards, setCards] = useState([]);

  const [userData, setUserData] = useState({ email: "" });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const navigate = useNavigate();

  const [isInfoTooltipOpen, setIsInfoTooltipOpen] = useState(false);
  const [tooltipMessage, setTooltipMessage] = useState("");
  const [isSuccess, setIsSuccess] = useState(false);

  async function handleCardLike(card) {
    const isLiked = card.isLiked;

    await api
      .likeCard(card._id, !isLiked)
      .then((newCard) => {
        setCards((state) =>
          state.map((currentCard) =>
            currentCard._id === card._id ? newCard : currentCard,
          ),
        );
      })
      .catch((error) => console.error(error));
  }

  useEffect(() => {
    api
      .getCards()
      .then((data) => setCards(data))
      .catch(console.error);
  }, []);

  useEffect(() => {
    (async () => {
      await api.getUserInfo().then((data) => {
        setCurrentUser(data);
      });
    })();
  }, []);

  const handleUpdateUser = (data) => {
    (async () => {
      await api
        .updateUser(data)
        .then((newData) => {
          setCurrentUser(newData);
          handleClosePopup();
        })
        .catch((error) => console.error(error));
    })();
  };

  const handleUpdateAvatar = (data) => {
    (async () => {
      await api
        .updateAvatar(data)
        .then((newData) => {
          setCurrentUser(newData);
          handleClosePopup();
        })
        .catch((error) => console.error(error));
    })();
  };

  const handleUpdateNewCard = (data) => {
    (async () => {
      await api
        .addCard(data)
        .then((newData) => {
          setCards((state) => [newData, ...state]);
          handleClosePopup();
        })
        .catch((error) => console.error(error));
    })();
  };

  function handleCardDelete(cardId) {
    api
      .deleteCard(cardId)
      .then(() => {
        setCards((state) => state.filter((card) => card._id !== cardId));
      })
      .catch(console.error);
  }

  function handleOpenPopup(popup) {
    setPopup(popup);
  }

  function handleClosePopup() {
    setPopup(null);
  }

  useEffect(() => {
    const jwt = token.getToken();
    if (jwt) {
      auth
        .checkToken(jwt)
        .then((res) => {
          setIsLoggedIn(true);
          setUserData({ email: res.data.email });
          navigate("/");
        })
        .catch((err) => {
          console.log(err);
          token.removeToken();
        });
    }
  }, [navigate]);

  const checkToken = () => {
    const token = localStorage.getItem("jwt");

    if (token) {
      auth
        .checkToken(token)
        .then((userData) => {
          setCurrentUser(userData);
          setIsLoggedIn(true);
        })
        .catch((error) => {
          localStorage.removeItem("jwt");
        });
    }
  };

  const handleRegistration = ({ email, password, confirmPassword }) => {
    if (password === confirmPassword) {
      auth
        .register(email, password)
        .then(() => {
          navigate("/signin");
        })
        .catch(console.error);
    }
  };

  const handleLogin = ({ email, password }) => {
    if (!email || !password) {
      return;
    }

    auth
      .authorize(email, password)
      .then((data) => {
        if (data.jwt) {
          token.setToken(data.jwt);
          setUserData(data.user);
          showTooltip("Login realizado com sucesso!", true);
          setIsLoggedIn(true);
          navigate("/");
        }
      })
      .catch((err) => {
        showTooltip("Ops, algo deu errado! Tente novamente.", false);
      });
  };

  const handleSignOut = () => {
    token.removeToken();
    setIsLoggedIn(false);
    setUserData({ email: "" });
    navigate("/signin");
  };

  const showTooltip = (message, success = false) => {
    setTooltipMessage(message);
    setIsSuccess(success);
    setIsInfoTooltipOpen(true);
  };

  const closeTooltip = () => {
    setIsInfoTooltipOpen(false);
  };

  return (
    <Routes>
      <Route
        path="/"
        element={
          <ProtectedRoute isLoggedIn={isLoggedIn}>
            <CurrentUserContext.Provider
              value={{ currentUser, handleUpdateUser, handleUpdateAvatar }}
            >
              <div className="page__content">
                <Header
                  isLoggedIn={isLoggedIn}
                  userEmail={userData.email}
                  handleSignOut={handleSignOut}
                />
                <Main
                  onOpenPopup={handleOpenPopup}
                  onClosePopup={handleClosePopup}
                  popup={popup}
                  cards={cards}
                  onCardLike={handleCardLike}
                  onCardDelete={handleCardDelete}
                  onCardAdd={handleUpdateNewCard}
                  handleSignOut={handleSignOut}
                />
                <Footer />
              </div>
              {popup && (
                <Popup onClose={handleClosePopup} title={popup.title}>
                  {popup.children}
                </Popup>
              )}
            </CurrentUserContext.Provider>
          </ProtectedRoute>
        }
      />
      <Route
        path="/signup"
        element={
          <div className="registerContainer">
            <Register handleRegistration={handleRegistration} />
            <InfoToolTip
              isOpen={isInfoTooltipOpen}
              onClose={closeTooltip}
              isSuccess={isSuccess}
              message={tooltipMessage}
            />
          </div>
        }
      />
      <Route
        path="/signin"
        element={
          <div className="loginContainer">
            <Login handleLogin={handleLogin} />
            <InfoToolTip
              isOpen={isInfoTooltipOpen}
              onClose={closeTooltip}
              isSuccess={isSuccess}
              message={tooltipMessage}
            />
          </div>
        }
      />
    </Routes>
  );
}

export default App;
